<?php
declare(strict_types=1);
require dirname(__DIR__).'/bootstrap.php';
use VP3\Projects\ProjectService;
$admin=vp3_require_admin_permission('projects.manage');$id=(int)vp3_input('id');$briefId=(int)vp3_input('brief_id');$service=new ProjectService(vp3_db());$row=null;$prefill=[];
if(!$id&&$briefId>0){$stmt=vp3_db()->prepare('SELECT pb.*,c.name customer_name,c.email customer_email FROM project_briefs pb JOIN customers c ON c.id=pb.customer_id WHERE pb.id=?');$stmt->execute([$briefId]);$brief=$stmt->fetch();if(is_array($brief))$prefill=['customer_id'=>$brief['customer_id'],'brief_id'=>$brief['id'],'title'=>$brief['project_name'],'summary'=>$brief['concept_summary'],'target_launch_date'=>$brief['target_launch_date']];}
if($id){$stmt=vp3_db()->prepare('SELECT p.*,c.name customer_name,c.email customer_email FROM creative_projects p JOIN customers c ON c.id=p.customer_id WHERE p.id=?');$stmt->execute([$id]);$row=$stmt->fetch();if(!$row){http_response_code(404);exit('Project not found.');}}
if(vp3_method()==='POST'){
    vp3_verify_csrf();$action=vp3_input('action','save');
    try{
        if($action==='save'){
            if($id){
                $creatorId=(int)vp3_input('creator_id');$showId=(int)vp3_input('show_id');$managerId=(int)vp3_input('project_manager_admin_id');
                if($managerId>0){$check=vp3_db()->prepare("SELECT COUNT(*) FROM admins WHERE id=? AND status='active'");$check->execute([$managerId]);if((int)$check->fetchColumn()<1)throw new RuntimeException('project_manager_not_available');}
                if($creatorId>0){$check=vp3_db()->prepare('SELECT COUNT(*) FROM creators WHERE id=? AND customer_id=?');$check->execute([$creatorId,$row['customer_id']]);if((int)$check->fetchColumn()<1)throw new RuntimeException('creator_customer_mismatch');}
                if($showId>0){$check=vp3_db()->prepare('SELECT COUNT(*) FROM shows WHERE id=? AND customer_id=?');$check->execute([$showId,$row['customer_id']]);if((int)$check->fetchColumn()<1)throw new RuntimeException('show_customer_mismatch');}
                $status=in_array(vp3_input('status'),['draft','active','paused','completed','archived'],true)?vp3_input('status'):'active';
                $phase=in_array(vp3_input('phase'),['discovery','strategy','development','production','launch','active','paused','completed','cancelled'],true)?vp3_input('phase'):'discovery';
                $health=in_array(vp3_input('health_status'),['on_track','at_risk','blocked','complete'],true)?vp3_input('health_status'):'on_track';
                vp3_db()->prepare("UPDATE creative_projects SET project_manager_admin_id=NULLIF(?,0),creator_id=NULLIF(?,0),show_id=NULLIF(?,0),title=?,project_type=?,summary=?,phase=?,health_status=?,target_launch_date=NULLIF(?,''),actual_launch_date=NULLIF(?,''),status=?,updated_at=NOW() WHERE id=?")
                    ->execute([$managerId,$creatorId,$showId,vp3_input('title'),vp3_input('project_type','media_platform'),vp3_input('summary'),$phase,$health,vp3_input('target_launch_date'),vp3_input('actual_launch_date'),$status,$id]);
                $service->recalculateReadiness($id);$service->activity($id,'admin',(int)$admin['id'],'project.updated','project',$row['project_uuid'],'Project details updated.');
            }else{
                $created=$service->create($_POST,(int)$admin['id']);$id=(int)$created['id'];
            }
        }elseif($action==='milestone'){$service->addMilestone($id,$_POST,(int)$admin['id']);}
        elseif($action==='task'){$service->addTask($id,$_POST,(int)$admin['id']);}
        elseif($action==='approval'){$service->requestApproval($id,$_POST,(int)$admin['id']);}
        elseif($action==='task_update'){
            $taskId=(int)vp3_input('task_id');$status=vp3_input('status');if(!in_array($status,['backlog','ready','in_progress','waiting','review','completed','cancelled'],true))throw new RuntimeException('invalid_task_status');
            $stmt=vp3_db()->prepare("UPDATE project_tasks SET status=?,started_at=CASE WHEN ?='in_progress' THEN COALESCE(started_at,NOW()) ELSE started_at END,completed_at=CASE WHEN ?='completed' THEN NOW() ELSE CASE WHEN ?<>'completed' THEN NULL ELSE completed_at END END,updated_at=NOW() WHERE id=? AND project_id=?");
            $stmt->execute([$status,$status,$status,$status,$taskId,$id]);if($stmt->rowCount()!==1)throw new RuntimeException('task_not_found');$service->recalculateReadiness($id);
        }
        elseif($action==='milestone_update'){
            $milestoneId=(int)vp3_input('milestone_id');$status=vp3_input('status');if(!in_array($status,['planned','active','at_risk','blocked','completed','cancelled'],true))throw new RuntimeException('invalid_milestone_status');
            $stmt=vp3_db()->prepare("UPDATE project_milestones SET status=?,completed_at=CASE WHEN ?='completed' THEN NOW() ELSE NULL END,updated_at=NOW() WHERE id=? AND project_id=?");
            $stmt->execute([$status,$status,$milestoneId,$id]);if($stmt->rowCount()!==1)throw new RuntimeException('milestone_not_found');
        }
        elseif($action==='comment'){
            $comment=vp3_input('comment');if(vp3_text_length($comment)<2)throw new RuntimeException('comment_required');
            vp3_db()->prepare("INSERT INTO project_comments(project_id,author_type,author_id,visibility,comment,created_at,updated_at) VALUES (?,'admin',?,?,?,NOW(),NOW())")->execute([$id,$admin['id'],vp3_input('visibility','shared'),$comment]);
            $service->activity($id,'admin',(int)$admin['id'],'comment.created','project',$row['project_uuid'],'VP3 added a project comment.');
        }elseif($action==='asset'){
            $title=vp3_input('asset_title');$url=vp3_public_https_url(vp3_input('external_url'));if($title===''||$url==='')throw new RuntimeException('asset_title_and_https_url_required');$uuid=vp3_uuid();
            vp3_db()->prepare("INSERT INTO project_assets(asset_uuid,project_id,uploaded_by_type,uploaded_by_id,category,title,description,external_url,visibility,approval_status,status,created_at,updated_at) VALUES (? ,?,'admin',?,?,?,?,?,?,?,'active',NOW(),NOW())")
                ->execute([$uuid,$id,$admin['id'],vp3_input('category','general'),$title,vp3_input('asset_description'),$url,vp3_input('visibility','shared'),vp3_input('approval_status','not_required')]);
            $service->activity($id,'admin',(int)$admin['id'],'asset.registered','asset',$uuid,'VP3 registered asset: '.$title);
        }elseif($action==='production_plan'){
            $title=vp3_input('plan_title');if($title==='')throw new RuntimeException('plan_title_required');$uuid=vp3_uuid();
            vp3_db()->prepare("INSERT INTO production_plans(plan_uuid,project_id,generated_by,generated_by_id,title,objective,status,version_number,created_at,updated_at) VALUES (?,?,'admin',?,?,?,'draft',1,NOW(),NOW())")->execute([$uuid,$id,$admin['id'],$title,vp3_input('objective')]);
            $service->activity($id,'admin',(int)$admin['id'],'production_plan.created','production_plan',$uuid,'Production plan foundation created.');
        }elseif($action==='plan_item'){
            $planId=(int)vp3_input('plan_id');$milestoneId=(int)vp3_input('milestone_id');$title=vp3_input('item_title');if($planId<1||$title==='')throw new RuntimeException('plan_and_item_required');
            $planCheck=vp3_db()->prepare('SELECT COUNT(*) FROM production_plans WHERE id=? AND project_id=?');$planCheck->execute([$planId,$id]);if((int)$planCheck->fetchColumn()<1)throw new RuntimeException('production_plan_not_found');
            if($milestoneId>0){$milestoneCheck=vp3_db()->prepare('SELECT COUNT(*) FROM project_milestones WHERE id=? AND project_id=?');$milestoneCheck->execute([$milestoneId,$id]);if((int)$milestoneCheck->fetchColumn()<1)throw new RuntimeException('milestone_project_mismatch');}
            $itemType=in_array(vp3_input('item_type'),['task_group','milestone','content','asset','review','launch_gate','risk'],true)?vp3_input('item_type'):'task_group';
            $ownerType=in_array(vp3_input('owner_type'),['vp3','customer','shared','external'],true)?vp3_input('owner_type'):'shared';
            vp3_db()->prepare("INSERT INTO production_plan_items(plan_id,milestone_id,title,description,item_type,target_date,owner_type,status,sort_order,created_at,updated_at) VALUES (?,NULLIF(?,0),?,?,?,?,?,'planned',?,NOW(),NOW())")
                ->execute([$planId,$milestoneId,vp3_text_slice($title,190),vp3_input('item_description'),$itemType,vp3_input('target_date')?:null,$ownerType,(int)vp3_input('sort_order','0')]);
        }
        vp3_flash('success','Project updated.');
    }catch(Throwable $e){vp3_flash('error',str_replace('_',' ',$e->getMessage()));}
    vp3_redirect('admin/project.php?id='.$id);
}
$customers=vp3_db()->query("SELECT id,name,email FROM customers WHERE status IN ('active','pending') ORDER BY name")->fetchAll();$admins=vp3_db()->query("SELECT id,name FROM admins WHERE status='active' ORDER BY name")->fetchAll();$creators=[];$shows=[];try{$creators=vp3_db()->query("SELECT id,display_name,customer_id FROM creators ORDER BY display_name")->fetchAll();$shows=vp3_db()->query("SELECT id,title,customer_id FROM shows ORDER BY title")->fetchAll();}catch(Throwable){}
$milestones=$tasks=$approvals=$assets=$comments=$activity=$plans=[];
if($id){
    $stmt=vp3_db()->prepare('SELECT * FROM project_milestones WHERE project_id=? ORDER BY sort_order,due_date,id');$stmt->execute([$id]);$milestones=$stmt->fetchAll();
    $stmt=vp3_db()->prepare('SELECT t.*,m.title milestone_title,a.name admin_name,c.name customer_name FROM project_tasks t LEFT JOIN project_milestones m ON m.id=t.milestone_id LEFT JOIN admins a ON a.id=t.assigned_admin_id LEFT JOIN customers c ON c.id=t.assigned_customer_id WHERE t.project_id=? ORDER BY FIELD(t.status,\'in_progress\',\'ready\',\'waiting\',\'review\',\'backlog\',\'completed\',\'cancelled\'),t.due_at');$stmt->execute([$id]);$tasks=$stmt->fetchAll();
    $stmt=vp3_db()->prepare('SELECT pa.*,a.title asset_title,t.title task_title FROM project_approvals pa LEFT JOIN project_assets a ON a.id=pa.asset_id LEFT JOIN project_tasks t ON t.id=pa.task_id WHERE pa.project_id=? ORDER BY FIELD(pa.status,\'pending\',\'revision_requested\',\'approved\',\'rejected\',\'cancelled\'),pa.created_at DESC');$stmt->execute([$id]);$approvals=$stmt->fetchAll();
    $stmt=vp3_db()->prepare("SELECT * FROM project_assets WHERE project_id=? AND status='active' ORDER BY updated_at DESC");$stmt->execute([$id]);$assets=$stmt->fetchAll();
    $stmt=vp3_db()->prepare('SELECT pc.*,a.name admin_name,c.name customer_name FROM project_comments pc LEFT JOIN admins a ON pc.author_type=\'admin\' AND a.id=pc.author_id LEFT JOIN customers c ON pc.author_type=\'customer\' AND c.id=pc.author_id WHERE pc.project_id=? ORDER BY pc.created_at DESC LIMIT 100');$stmt->execute([$id]);$comments=$stmt->fetchAll();
    $stmt=vp3_db()->prepare('SELECT * FROM project_activity WHERE project_id=? ORDER BY created_at DESC LIMIT 100');$stmt->execute([$id]);$activity=$stmt->fetchAll();
    $stmt=vp3_db()->prepare('SELECT pp.*,(SELECT COUNT(*) FROM production_plan_items ppi WHERE ppi.plan_id=pp.id) item_count FROM production_plans pp WHERE pp.project_id=? ORDER BY version_number DESC');$stmt->execute([$id]);$plans=$stmt->fetchAll();
    $stmt=vp3_db()->prepare('SELECT p.*,c.name customer_name,c.email customer_email FROM creative_projects p JOIN customers c ON c.id=p.customer_id WHERE p.id=?');$stmt->execute([$id]);$row=$stmt->fetch();
}
