?></option><?php endforeach;?></select></div><div class="field"><label>Type</label><input name="task_type" value="general"></div><div class="field"><label>Priority</label><select name="priority"><option>normal</option><option>low</option><option>high</option><option>urgent</option></select></div><div class="field"><label>Status</label><select name="status"><option>ready</option><option>backlog</option><option>in_progress</option><option>waiting</option><option>review</option></select></div><div class="field"><label>Due</label><input type="datetime-local" name="due_at"></div><div class="field"><label>Estimated minutes</label><input type="number" min="0" name="estimated_minutes"></div></div><button class="button small">Add task</button></form></section>
