<section class="admin-section admin-split"><div><h2>Production plans</h2><?php foreach($plans as $p):?><article class="card"><span class="badge <?=vp3_e($p['status'])?>"><?=vp3_e($p['status'])?></span><h3><?=vp3_e($p['title'])?></h3><p><?=vp3_e($p['objective'])?></p><small>Version <?=(int)$p['version_number']?> · <?=(int)$p['item_count']?> items</small></article><?php endforeach;?></div><div><form class="card" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="production_plan"><h3>Create production plan</h3><div class="field"><label>Title</label><input name="plan_title" required></div><div class="field"><label>Objective</label><textarea name="objective"></textarea></div><button class="button small">Create draft plan</button></form><?php if($plans):?><form class="card admin-section" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="plan_item"><h3>Add plan item</h3><div class="field"><label>Plan</label><select name="plan_id"><?php foreach($plans as $p):?><option value="<?=(int)$p['id']?>"><?=vp3_e($p['title'])?></option><?php endforeach;?></select></div><div class="field"><label>Milestone</label><select name="milestone_id"><option value="0">None</option><?php foreach($milestones as $m):?><option value="<?=(int)$m['id']?>"><?=vp3_e($m['title'])?></option><?php endforeach;?></select></div><div class="field"><label>Title</label><input name="item_title" required></div><div class="field"><label>Description</label><textarea name="item_description"></textarea></div><div class="field"><label>Type</label><select name="item_type"><option>task_group</option><option>milestone</option><option>content</option><option>asset</option><option>review</option><option>launch_gate</option><option>risk</option></select></div><div class="field"><label>Owner</label><select name="owner_type"><option>shared</option><option>vp3</option><option>customer</option><option>external</option></select></div><div class="field"><label>Target date</label><input name="target_date" type="date"></div><button class="button small">Add plan item</button></form><?php endif;?></div></section>
<section class="admin-section admin-split"><div><h2>Comments</h2><form class="card" method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="comment"><div class="field"><label>Comment</label><textarea name="comment" required></textarea></div><div class="field"><label>Visibility</label><select name="visibility"><option>shared</option><option>internal</option><option>customer</option></select></div><button class="button small">Post comment</button></form><div class="activity-list"><?php foreach($comments as $c):?><article><strong><?=vp3_e($c['admin_name']?:$c['customer_name']?:ucfirst($c['author_type']))?></strong><span><?=vp3_e($c['visibility'].' · '.$c['created_at'])?></span><p><?=nl2br(vp3_e($c['comment']))?></p></article><?php endforeach;?></div></div><div><h2>Activity</h2><div class="activity-list"><?php foreach($activity as $a):?><article><strong><?=vp3_e($a['summary'])?></strong><span><?=vp3_e($a['actor_type'].' · '.$a['created_at'])?></span></article><?php endforeach;?></div></div></section><?php endif;?>
